    81→    const res = await apiFetch<{ user: User; token: string }>('/api/auth/register', {
    82→      method: 'POST',
    83→      body: JSON.stringify(data),
    84→    });
    85→    await setToken(res.token);
    86→    setTokenState(res.token);
    87→    setUser(res.user);
    88→  }
    89→
    90→  async function logout() {
    91→    await clearToken();
    92→    setTokenState(null);
    93→    setUser(null);
    94→  }
    95→
    96→  async function refreshUser() {
    97→    try {
    98→      const me = await apiFetch<User>('/api/users/me');
    99→      setUser(me);
   100→    } catch { /* ignore */ }
   101→  }
   102→
   103→  const value = useMemo(() => ({
   104→    user, token, isLoading, login, register, logout, refreshUser
   105→  }), [user, token, isLoading]);
   106→
   107→  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
   108→}
