      [req.params.id, 'Account Verified', 'Your account has been manually verified by the Flism team. Trust score +50 pts.', 'success']
    );
    res.json(result.rows[0]);
  } catch (err) {
    res.status(500).json({ error: 'Server error' });
  }
});

